```python
"""
This module represents a checkers player.
"""

class Player:
    def __init__(self, name, color):
        self.name = name
        self.color = color

    def get_move(self):
        # Placeholder for move input
        return input(f"{self.name}, enter your move (e.g., A1-B2): ").upper()
```

#### `game.py`

```python
"""
This module orchestrates the checkers game.
"""

from board import Board, Piece
from player import Player

class Game:
    def __init__(self):
        self.board = Board()
        self.players = [Player("Player 1", "black"), Player("Player 2", "white")]
        self.current_player_index = 0

    def switch_turn(self):
        self.current_player_index = (self.current_player_index + 1) % 2

    def play(self):
        while True:
            current_player = self.players[self.current_player_index]
            print("\nCurrent Board:")
            self.board.display()
            move = current_player.get_move()

            # Placeholder for actual move validation and execution
            print(f"{current_player.name} moved: {move}")

            if self.check_game_over():
                print("Game Over!")
                break

            self.switch_turn()

    def check_game_over(self):
        # Placeholder for game over logic
        return False
```

